            if plantId then ids[tostring(plantId)] = true end
            local fruitsF = plant:FindFirstChild("Fruits")
            if fruitsF then
                for _, fruit in pairs(fruitsF:GetChildren()) do
                    ids._fruits[fruit] = true
                    local fruitId = fruit:GetAttribute("FruitId")
